import 'package:flutter_riverpod/flutter_riverpod.dart'; import '../../../../services/api_service.dart'; final deliveryProvider = StateNotifierProvider<DeliveryNotifier, DeliveryState>((ref)=>DeliveryNotifier(ref)); class DeliveryOrder { final int id; final String customerName, customerPhone; DeliveryOrder({required this.id, required this.customerName, required this.customerPhone}); } class DeliveryState { final List<DeliveryOrder> orders; final bool loading; DeliveryState({this.orders=const[], this.loading=false}); DeliveryState copyWith({List<DeliveryOrder>? orders, bool? loading}) => DeliveryState(orders: orders??this.orders, loading: loading??this.loading); } class DeliveryNotifier extends StateNotifier<DeliveryState> { final Ref ref; DeliveryNotifier(this.ref) : super(DeliveryState()); Future<void> load() async { state = state.copyWith(loading:true); final api = ref.read(apiServiceProvider); final data = await api.getDeliveryOrders(); state = state.copyWith(orders: data.map((e)=>DeliveryOrder(id:e['id'], customerName:e['customer_name'], customerPhone:e['customer_phone'])).toList(), loading:false); } Future<void> updateStatus(int id, String status) async { final api = ref.read(apiServiceProvider); await api.updateOrderStatus(id, status); load(); } }
